import { cva, type VariantProps } from "class-variance-authority";
import type { FlattenIntersection } from "@/lib/types/helpers";
import { cn } from "@/lib/utils/cn";
import { Typography, type TypographyProps } from "./typography";

const textVariants = cva(null, {
	variants: {
		size: {
			xxxs: "text-12",
			xxs: "text-13",
			xs: "text-14",
			s: "text-15",
			m: "text-16",
			l: "text-17",
			xl: "text-18",
			xxl: "text-19",
			xxxl: "text-20",
		},
	},
});

export type TextVariants = VariantProps<typeof textVariants>;
export type TextProps = FlattenIntersection<TypographyProps & TextVariants>;

export const Text = ({
	className,
	size = "m",
	emphasis = "high",
	as = "span",
	...props
}: TextProps) => (
	<Typography
		className={cn(textVariants({ size }), className)}
		emphasis={emphasis}
		{...props}
	></Typography>
);

import { cva, type VariantProps } from "class-variance-authority";
import type { FlattenIntersection } from "@/lib/types/helpers";
import { cn } from "@/lib/utils/cn";
import { Typography, type TypographyProps } from "./typography";

const titleVariants = cva("fw-11d", {
	variants: {
		size: {
			xxs: "text-15",
			xs: "text-16",
			s: "text-17",
			m: "text-18",
			l: "text-19",
			xl: "text-20",
			xxl: "text-21",
		},
	},
});

export type TitleVariants = VariantProps<typeof titleVariants>;
export type TitleProps = FlattenIntersection<TypographyProps & TitleVariants>;

export const Title = ({
	className,
	size = "xxl",
	emphasis = "high",
	as = "h1",
	...props
}: TitleProps) => (
	<Typography
		className={cn(titleVariants({ size }), className)}
		emphasis={emphasis}
		{...props}
	></Typography>
);

import type { FlattenIntersection } from "@/lib/types/helpers";
import { cn } from "@/lib/utils/cn";
import type { CompoundProps } from "../types";
import { Variants } from "../variants";

export type TypographyProps = FlattenIntersection<
	Variants.EmphasisSurface &
		CompoundProps & {
			as?: React.ElementType;
		}
>;

export const Typography = ({
	as: Tag = "span",
	emphasis,
	className,
	...props
}: TypographyProps) => {
	return (
		<Tag
			className={cn(
				"sfc-text sfc-color-default-on-default",
				Variants.emphasisSurfaceVariants({ emphasis }),
				className,
			)}
			{...props}
		/>
	);
};
